document.querySelector(".shop").addEventListener("mousemove",e=>{const t=e.pageX/window.innerWidth,r=e.pageY/window.innerHeight;document.querySelector(".hearts").style.transform="translate("+20*t+"px, "+25*r+"px)",document.querySelector(".inst").style.transform="translate(-"+40*t+"px, -"+20*r+"px)",document.querySelector(".hearts_bot").style.transform="translate("+30*t+"px, "+20*r+"px) rotate(40deg)",document.querySelector(".inst_bot").style.transform="translate(-"+25*t+"px, -"+25*r+"px)"}),document.querySelector(".news").addEventListener("mousemove",e=>{const t=e.pageX/window.innerWidth,r=e.pageY/window.innerHeight;document.querySelector(".news__teleg-top").style.transform="translate(-"+40*t+"px, -"+10*r+"px)",document.querySelector(".news__teleg-bot").style.transform="translate("+30*t+"px, "+20*r+"px) rotate(-20deg)"}),$(document).ready((function(){$(".use__slider").slick({variableWidth:!1,variableHeight:!1,fade:!0,arrows:!1,asNavFor:".slick__dots"})})),$(".slick__dots").slick({slidesToShow:4,asNavFor:".use__slider",variableWidth:!1,arrows:!1,focusOnSelect:!0});